    parts = s.split('.')
    if len(parts) != 4:
        return False
    for part in parts:
        if not part.isdigit():
            return False
        if part != '0' and part.startswith('0'):
            return False
        value = int(part)
        if value < 0 or value > 255:
            return False
    return True

