from heapq import heappush, heappop

def shortest_path_weighted(num_nodes, edges, start, end):
    graph = [[] for _ in range(num_nodes)]
    for u, v, w in edges:
        graph[u].append((v, w))
    dist = [float('inf')] * num_nodes
    parent = [-1] * num_nodes
    dist[start] = 0
    heap = [(0, start)]
    while heap:
        d, node = heappop(heap)
        if d != dist[node]:
            continue
        if node == end:
            break
        for nei, w in graph[node]:
            nd = d + w
            if nd < dist[nei]:
                dist[nei] = nd
                parent[nei] = node
                heappush(heap, (nd, nei))
    if dist[end] == float('inf'):
        return (float('inf'), [])
    path = []
    cur = end
    while cur != -1:
        path.append(cur)
        cur = parent[cur]
    path.reverse()
    return (dist[end], path)

