import functools

def largest_number(nums):
    strs = list(map(str, nums))
    def cmp(a, b):
        if a + b > b + a:
            return -1
        if a + b < b + a:
            return 1
        return 0
    strs.sort(key=functools.cmp_to_key(cmp))
    result = ''.join(strs).lstrip('0')
    return result or '0'

