import heapq

def median_stream(nums):
    lowers = []
    uppers = []
    out = []
    for n in nums:
        if not lowers or n <= -lowers[0]:
            heapq.heappush(lowers, -n)
        else:
            heapq.heappush(uppers, n)
        if len(lowers) > len(uppers) + 1:
            heapq.heappush(uppers, -heapq.heappop(lowers))
        if len(uppers) > len(lowers):
            heapq.heappush(lowers, -heapq.heappop(uppers))
        if len(lowers) == len(uppers):
            out.append(((-lowers[0]) + uppers[0]) / 2)
        else:
            out.append(float(-lowers[0]))
    return out

