from math import gcd

def max_points(points):
    if len(points) < 2:
        return len(points)
    best = 0
    for i in range(len(points)):
        slopes = {}
        same = 1
        for j in range(i + 1, len(points)):
            x1, y1 = points[i]
            x2, y2 = points[j]
            dx = x2 - x1
            dy = y2 - y1
            if dx == 0 and dy == 0:
                same += 1
                continue
            g = gcd(dx, dy)
            dx //= g
            dy //= g
            if dx < 0:
                dx, dy = -dx, -dy
            elif dx == 0:
                dy = 1
            slopes[(dx, dy)] = slopes.get((dx, dy), 0) + 1
        current = same
        for count in slopes.values():
            current = max(current, count + same)
        best = max(best, current)
    return best

