def palindrome_pairs(words):
    index = {w: i for i, w in enumerate(words)}
    res = []
    def is_pal(s):
        return s == s[::-1]
    for i, w in enumerate(words):
        for split in range(len(w) + 1):
            left = w[:split]
            right = w[split:]
            if is_pal(left):
